:root {
  --color-bg: #000000;
  --color-surface: #111111;
  --color-surface-alt: #181818;
  --color-primary: #ff00cc;
  --color-primary-soft: #ff4de0;
  --color-secondary: #00d4ff;
  --color-tertiary: #8000ff;
  --color-text: #ffffff;
  --color-muted: #f5f5f5;
  --color-border-subtle: #222222;

  --color-success: #3ddc97;
  --color-error: #ff4b4b;
  --color-warning: #ffc857;
  --color-info: #2196f3;

  --font-heading: "Space Grotesk", -apple-system, BlinkMacSystemFont, "Helvetica Neue", Helvetica, Arial, sans-serif;
  --font-body: "IBM Plex Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif;

  --font-size-xs: 0.75rem;
  --font-size-sm: 0.8125rem;
  --font-size-base: 1rem;
  --font-size-md: 1.125rem;
  --font-size-lg: 1.5rem;
  --font-size-xl: 2.25rem;
  --font-size-xxl: 3.5rem;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.15;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;
  --space-8: 96px;

  --radius-pill: 9999px;
  --radius-soft: 8px;

  --shadow-soft: 0 14px 30px rgba(0, 0, 0, 0.6);

  --transition-fast: 150ms ease-out;
  --transition-med: 220ms ease-out;

  --max-width-content: 1120px;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body.site-body {
  min-height: 100vh;
  background-color: var(--color-bg);
  color: var(--color-text);
  font-family: var(--font-body);
  font-size: var(--font-size-base);
  line-height: var(--line-height-normal);
  -webkit-font-smoothing: antialiased;
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:focus-visible,
button:focus-visible,
[role="button"]:focus-visible,
input:focus-visible {
  outline: 2px solid var(--color-secondary);
  outline-offset: 3px;
}

.site-wrapper {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

.site-main {
  flex: 1 0 auto;
  max-width: var(--max-width-content);
  margin: 0 auto;
  padding: var(--space-7) var(--space-3) var(--space-8);
  font-size: var(--font-size-md);
}

/* Header */

.site-header {
  flex: 0 0 auto;
  padding: var(--space-4) var(--space-3) 0;
  background-color: var(--color-bg);
  position: relative;
  z-index: 20;
}

.header-inner {
  max-width: var(--max-width-content);
  margin: 0 auto;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.brand {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-bold);
  font-size: 1.25rem;
  letter-spacing: 0.18em;
  text-transform: lowercase;
  line-height: 1;
  display: inline-flex;
  align-items: baseline;
  gap: 0.15em;
}

.brand-mark {
  background-image: linear-gradient(90deg, #ff00cc 0%, #00d4ff 45%, #8000ff 100%);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
}

.brand-mark--second {
  background-image: linear-gradient(90deg, #00d4ff 0%, #8000ff 60%, #ff00cc 100%);
}

.brand--small {
  font-size: 1rem;
}

/* Header actions */

.header-actions {
  display: inline-flex;
  align-items: center;
  gap: var(--space-3);
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.75rem 1.75rem;
  border-radius: var(--radius-pill);
  border: none;
  font-family: var(--font-heading);
  font-weight: var(--font-weight-medium);
  font-size: 0.95rem;
  letter-spacing: 0.06em;
  text-transform: none;
  cursor: pointer;
  transition: background-color var(--transition-med), transform var(--transition-fast), box-shadow var(--transition-med);
}

.btn-primary {
  background: var(--color-primary);
  color: var(--color-text);
  box-shadow: var(--shadow-soft);
  white-space: nowrap;
}

.btn-primary:hover {
  background: var(--color-primary-soft);
  transform: translateY(-1px);
}

.btn-primary:active {
  transform: translateY(0);
  box-shadow: none;
}

/* Circular nav toggle */

.nav-toggle-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
}

.nav-toggle-circle {
  width: 44px;
  height: 44px;
  border-radius: 999px;
  border: 2px solid var(--color-primary);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 5px;
  transition: background-color var(--transition-med), border-color var(--transition-med), transform var(--transition-fast);
}

.nav-toggle-line {
  width: 16px;
  height: 2px;
  border-radius: 99px;
  background-color: var(--color-text);
}

.nav-toggle-btn:hover .nav-toggle-circle {
  background-color: rgba(255, 0, 204, 0.15);
  border-color: var(--color-primary-soft);
  transform: translateY(-1px);
}

/* Hidden checkbox */

.nav-toggle {
  position: absolute;
  opacity: 0;
  pointer-events: none;
}

/* Nav overlay */

.primary-nav-panel {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.96);
  backdrop-filter: blur(18px);
  -webkit-backdrop-filter: blur(18px);
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  visibility: hidden;
  transform: translateY(-12px);
  transition: opacity var(--transition-med), visibility var(--transition-med), transform var(--transition-med);
}

.primary-nav-panel-inner {
  max-width: var(--max-width-content);
  width: 100%;
  padding: 0 var(--space-3);
}

.primary-nav-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: grid;
  gap: var(--space-3);
  text-align: left;
}

.primary-nav-item {
  font-family: var(--font-heading);
  font-size: var(--font-size-xl);
  font-weight: var(--font-weight-semibold);
  line-height: var(--line-height-tight);
}

.primary-nav-link {
  display: inline-block;
  padding: 0.15em 0;
  color: var(--color-text);
  position: relative;
}

.primary-nav-link::after {
  content: "";
  position: absolute;
  left: 0;
  bottom: -4px;
  width: 0;
  height: 2px;
  background: linear-gradient(90deg, var(--color-primary), var(--color-secondary), var(--color-tertiary));
  transition: width var(--transition-med);
}

.primary-nav-link:hover::after {
  width: 100%;
}

/* Open state via checkbox */

.nav-toggle:checked + .primary-nav-panel {
  opacity: 1;
  visibility: visible;
  transform: translateY(0);
}

/* Footer */

.site-footer {
  flex: 0 0 auto;
  background-color: var(--color-bg);
  border-top: 1px solid var(--color-border-subtle);
  padding: var(--space-6) var(--space-3) var(--space-4);
}

.footer-inner {
  max-width: var(--max-width-content);
  margin: 0 auto;
  display: grid;
  grid-template-columns: minmax(0, 2fr) minmax(0, 3fr);
  gap: var(--space-5);
  align-items: flex-start;
}

.footer-brand {
  max-width: 320px;
}

.footer-tagline {
  margin: var(--space-3) 0 0;
  font-size: var(--font-size-md);
  color: rgba(255, 255, 255, 0.78);
  line-height: var(--line-height-relaxed);
}

.footer-links {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: var(--space-5);
}

.footer-heading {
  font-family: var(--font-heading);
  font-size: 0.9rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.68);
  margin: 0 0 var(--space-3);
}

.footer-link-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  gap: var(--space-2);
}

.footer-link-list a {
  font-size: 0.95rem;
  color: rgba(255, 255, 255, 0.9);
  transition: color var(--transition-fast);
}

.footer-link-list a:hover {
  color: var(--color-primary-soft);
}

.footer-bottom {
  max-width: var(--max-width-content);
  margin: var(--space-4) auto 0;
  padding-top: var(--space-3);
  border-top: 1px solid var(--color-border-subtle);
  font-size: var(--font-size-xs);
  color: rgba(255, 255, 255, 0.6);
}

.footer-meta {
  margin: 0;
}

/* Responsive */

@media (max-width: 960px) {
  .site-header {
    padding-top: var(--space-3);
  }

  .btn-primary {
    padding-inline: 1.3rem;
  }

  .site-main {
    padding-top: var(--space-6);
  }

  .primary-nav-item {
    font-size: 1.75rem;
  }
}

@media (max-width: 768px) {
  .header-inner {
    padding-inline: 0;
  }

  .site-header {
    padding-inline: var(--space-3);
  }

  .site-main {
    padding-inline: var(--space-3);
  }

  .footer-inner {
    grid-template-columns: 1fr;
  }

  .footer-links {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 480px) {
  .btn-primary {
    display: none;
  }

  .footer-tagline {
    font-size: var(--font-size-base);
  }
}
